import { db } from "./mongoClient";

type CaptionEntry = {
  caption: string;
  score: number;
};

const storedCaptions: CaptionEntry[] = [];

export async function getPastInstagramCaptions(): Promise<string[]> {
  const docs = await db.collection("captions").find().sort({ createdAt: -1 }).limit(50).toArray();
  return docs.map((d: any) => d.text);
}

export async function saveInstagramCaption(text: string) {
  return db.collection("captions").insertOne({ text, createdAt: new Date() });
}

export async function storeCaption(caption: string, engagement: number, hashtags: string[]) {
  return db.collection("captions").insertOne({ 
    caption, 
    engagement, 
    hashtags, 
    createdAt: new Date() 
  });
}

export async function saveCaptionPerformance(captionText: string, score: number) {
  const collection = db.collection('captions');
  await collection.insertOne({
    captionText,
    performanceScore: score,
    timestamp: new Date(),
  });
  
  // Also store in memory for quick access
  storedCaptions.push({ caption: captionText, score });
  storedCaptions.sort((a, b) => b.score - a.score);
  if (storedCaptions.length > 20) storedCaptions.pop(); // Keep top 20
}

export async function fetchTopCaptionsFromDB(): Promise<string[]> {
  return storedCaptions.slice(0, 3).map((c) => c.caption);
} 